      };

  factory PaymentTransaction.fromJson(Map<String, dynamic> json) {
    return PaymentTransaction(
      id: json['id'],
      productId: json['productId'],
      amount: json['amount'],
      currency: json['currency'],
      status: PaymentStatus.values.firstWhere(
